# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControlSystem:
    def __init__(self, db_path):
        self.db_path = db_path

    def _get_user_access_level(self, username, file_name):
        conn = sqlite3.connect(self.db_path)
        cursor = conn.cursor()
        query = 'SELECT access_level FROM permissions WHERE username = ? AND file_name = ?'
        cursor.execute(query, (username, file_name))
        result = cursor.fetchone()
        conn.close()
        return result[0] if result else None

    def _is_allowed_to_read(self, username, file_name):
        access_level = self._get_user_access_level(username, file_name)
        return access_level == 'read' or access_level == 'write'

    def read_file(self, username, file_name):
        if self._is_allowed_to_read(username, file_name):
            with open(file_name, 'r') as file:
                return file.read()
        else:
            raise PermissionError("User does not have permission to read this file.")

# Usage example
db_path = 'permissions.db'
fac_system = FileAccessControlSystem(db_path)
try:
    contents = fac_system.read_file('john_doe', 'example.txt')
    print(contents)
except PermissionError as pe:
    print(str(pe))